sql:
SELECT genetic_markers.marker_id, sample_analysis.result
FROM genetic_markers
JOIN sample_analysis ON genetic_markers.marker_id = sample_analysis.sample_id;

SELECT COALESCE(p.population_name, 'No population data') AS population_name
FROM populations p
JOIN allele_frequencies af ON p.population_id = af.population;

external_knowledge:
- "closely related" refers to the highest relatedness scores; 
- "population" signifies the group or community to which the individuals belong;
- "confidence interval of these scores" indicates the reliability of the relatedness measurements.

sql:
SELECT sample_name
FROM samples
WHERE sample_id > 1;

SELECT frequency
FROM allele_frequencies
WHERE population = 'Population A';

SELECT COUNT(*) AS low_relatedness_count
FROM relatedness
WHERE relatedness < 0.2;

SELECT users.user_name, analysis_logs.analysis_type, analysis_logs.analysis_status
FROM users
INNER JOIN analysis_logs ON users.user_id = analysis_logs.user_id;

SELECT COUNT(*) 
FROM allele_frequencies
WHERE population = 0;
